import 'package:flutter/material.dart'; import 'package:flutter_riverpod/flutter_riverpod.dart'; import '../../../../core/widgets/app_empty_view.dart'; import '../../../../core/widgets/app_loading_view.dart'; import '../../../product/presentation/widgets/product_preview_card.dart'; import '../providers/search_providers.dart'; import '../widgets/search_filter_sheet.dart';
class SearchPage extends ConsumerStatefulWidget{const SearchPage({super.key}); @override ConsumerState<SearchPage> createState()=>_SearchPageState();}
class _SearchPageState extends ConsumerState<SearchPage>{final controller=TextEditingController(); @override void dispose(){controller.dispose();super.dispose();} @override Widget build(BuildContext context){final async=ref.watch(searchResultsProvider); return Scaffold(appBar:AppBar(title:TextField(controller:controller,autofocus:true,decoration:const InputDecoration(hintText:'Search products...'),onChanged:(v)=>ref.read(searchControllerProvider.notifier).updateKeyword(v),onSubmitted:(v)=>ref.read(searchControllerProvider.notifier).submitSearch(v)),actions:[IconButton(onPressed:()=>showModalBottomSheet<void>(context:context,builder:(_)=>const SearchFilterSheet()),icon:const Icon(Icons.tune))]),body:async.when(loading:()=>const AppLoadingView(),error:(e,_)=>AppEmptyView(title:'Error',message:e.toString()),data:(items)=>items.isEmpty?const AppEmptyView(title:'Product မတွေ့ပါ'):GridView.builder(padding:const EdgeInsets.all(12),gridDelegate:const SliverGridDelegateWithFixedCrossAxisCount(crossAxisCount:2,childAspectRatio:.72),itemCount:items.length,itemBuilder:(_,i)=>ProductPreviewCard(product:items[i]))));}}
